import React, { useEffect, useMemo, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import {
  Alert,
  Badge,
  Button,
  Card,
  Col,
  Container,
  Form,
  Row,
  Spinner,
} from "react-bootstrap";
import api from "../services/api";

function EventDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [event, setEvent] = useState(null);
  const [ticketTypes, setTicketTypes] = useState([]);
  const [summary, setSummary] = useState(null);
  const [quantities, setQuantities] = useState({});
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const getStoredUser = () => {
    try {
      const rawUser = localStorage.getItem("user");
      if (!rawUser || rawUser === "undefined") return null;
      return JSON.parse(rawUser);
    } catch (error) {
      localStorage.removeItem("user");
      return null;
    }
  };

  const user = getStoredUser();

  const getBannerSrc = (bannerImage) => {
    if (!bannerImage) {
      return "https://via.placeholder.com/1200x700?text=Concert+Banner";
    }

    if (
      bannerImage.startsWith("http://") ||
      bannerImage.startsWith("https://")
    ) {
      return bannerImage;
    }

    return `/images/${bannerImage}`;
  };

  const getEventStatusText = (status) => {
    switch (status) {
      case "draft":
        return "Nháp";
      case "upcoming":
        return "Sắp mở bán";
      case "on_sale":
        return "Đang mở bán";
      case "paused":
        return "Tạm dừng";
      case "sold_out":
        return "Hết vé";
      case "ended":
        return "Đã kết thúc";
      case "cancelled":
        return "Đã hủy";
      default:
        return "Không xác định";
    }
  };

  const getEventStatusVariant = (status) => {
    switch (status) {
      case "on_sale":
        return "success";
      case "upcoming":
        return "warning";
      case "sold_out":
      case "ended":
      case "cancelled":
        return "secondary";
      case "paused":
        return "danger";
      default:
        return "dark";
    }
  };

  const formatDateTime = (dateString) => {
    if (!dateString) return "Không có dữ liệu";

    const date = new Date(dateString);

    return date.toLocaleString("vi-VN", {
      weekday: "long",
      year: "numeric",
      month: "long",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    });
  };

  useEffect(() => {
    const fetchEventDetail = async () => {
      try {
        setLoading(true);
        setError("");

        const response = await api.get(`/events/${id}/details`);

        if (response.data?.success && response.data?.data) {
          const payload = response.data.data;
          const eventData = payload.event || null;
          const ticketList = payload.ticketTypes || [];
          const summaryData = payload.summary || null;

          setEvent(eventData);
          setTicketTypes(ticketList);
          setSummary(summaryData);

          const initialQuantities = {};
          ticketList.forEach((ticket) => {
            initialQuantities[ticket.id] = 0;
          });
          setQuantities(initialQuantities);
        } else {
          setError("Không lấy được chi tiết sự kiện");
        }
      } catch (err) {
        console.error("Lỗi khi tải chi tiết sự kiện:", err);
        setError(
          err.response?.data?.message || "Lỗi khi tải chi tiết sự kiện"
        );
      } finally {
        setLoading(false);
      }
    };

    fetchEventDetail();
  }, [id]);

  const handleQuantityChange = (ticket, value) => {
    let quantity = Number(value);

    if (Number.isNaN(quantity) || quantity < 0) quantity = 0;

    const maxAllowed = Math.min(
      Number(ticket.available || 0),
      Number(ticket.max_per_order || 0)
    );

    if (quantity > maxAllowed) quantity = maxAllowed;

    setQuantities((prev) => ({
      ...prev,
      [ticket.id]: quantity,
    }));
  };

  const totalTickets = useMemo(() => {
    return ticketTypes.reduce((sum, ticket) => {
      return sum + Number(quantities[ticket.id] || 0);
    }, 0);
  }, [ticketTypes, quantities]);

  const totalAmount = useMemo(() => {
    return ticketTypes.reduce((sum, ticket) => {
      const qty = Number(quantities[ticket.id] || 0);
      return sum + qty * Number(ticket.price || 0);
    }, 0);
  }, [ticketTypes, quantities]);

  const canBuy = ticketTypes.some(
    (ticket) =>
      Number(ticket.available || 0) > 0 &&
      Number(ticket.max_per_order || 0) > 0 &&
      ticket.status === "active"
  );

  const handleCreateOrder = async () => {
    try {
      setError("");
      setSuccess("");

      const token = localStorage.getItem("token");
      if (!token || !user) {
        navigate("/login");
        return;
      }

      const items = ticketTypes
        .filter((ticket) => Number(quantities[ticket.id] || 0) > 0)
        .map((ticket) => ({
          ticket_type_id: ticket.id,
          quantity: Number(quantities[ticket.id]),
        }));

      if (items.length === 0) {
        setError("Vui lòng chọn ít nhất 1 vé");
        return;
      }

      setSubmitting(true);

      const response = await api.post("/users/orders/create", { items });

      if (response.data?.success) {
        const orderId = response.data.data?.orderId;

        setSuccess("Đặt vé thành công, đang chuyển sang thanh toán...");

        setTimeout(() => {
          navigate(`/payment/${orderId}`);
        }, 700);
      } else {
        setError(response.data?.message || "Đặt vé thất bại");
      }
    } catch (err) {
      console.error("Lỗi tạo đơn hàng:", err);
      setError(err.response?.data?.message || "Đã xảy ra lỗi khi đặt vé");
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div
        className="d-flex justify-content-center align-items-center"
        style={{ minHeight: "70vh" }}
      >
        <Spinner animation="border" />
      </div>
    );
  }

  if (error && !event) {
    return (
      <Container className="user-shell text-center">
        <h3>{error}</h3>
      </Container>
    );
  }

  if (!event) {
    return (
      <Container className="user-shell text-center">
        <h3>Không tìm thấy sự kiện này.</h3>
      </Container>
    );
  }

  return (
    <Container className="user-shell">
      <Row className="g-4">
        <Col lg={8}>
          <Card className="payment-card overflow-hidden">
            <div
              style={{
                height: "420px",
                overflow: "hidden",
                background: "#e5e7eb",
              }}
            >
              <img
                src={getBannerSrc(event.banner_image)}
                alt={event.title}
                style={{
                  width: "100%",
                  height: "100%",
                  objectFit: "cover",
                }}
                onError={(e) => {
                  e.target.src =
                    "https://via.placeholder.com/1200x700?text=Concert+Banner";
                }}
              />
            </div>

            <Card.Body className="p-4 p-lg-5">
              {error && <Alert variant="danger">{error}</Alert>}
              {success && <Alert variant="success">{success}</Alert>}

              <div className="d-flex flex-wrap align-items-center gap-3 mb-3">
                <Badge
                  bg={getEventStatusVariant(event.status)}
                  className="status-badge"
                >
                  {getEventStatusText(event.status)}
                </Badge>

                {summary?.hasAvailableTickets ? (
                  <span className="info-pill">🎫 Còn vé</span>
                ) : (
                  <span className="info-pill">⛔ Không còn vé</span>
                )}
              </div>

              <div className="section-title mb-3">{event.title}</div>

              <div className="section-subtitle mb-4">
                {event.description || "Không có mô tả cho sự kiện này."}
              </div>

              <Row className="g-3">
                <Col md={6}>
                  <div className="payment-summary-box h-100">
                    <div className="text-muted mb-1">Địa điểm</div>
                    <div className="fw-bold">{event.location}</div>
                  </div>
                </Col>

                <Col md={6}>
                  <div className="payment-summary-box h-100">
                    <div className="text-muted mb-1">Thời gian diễn ra</div>
                    <div className="fw-bold">{formatDateTime(event.event_date)}</div>
                  </div>
                </Col>

                <Col md={6}>
                  <div className="payment-summary-box h-100">
                    <div className="text-muted mb-1">Mở check-in</div>
                    <div className="fw-bold">
                      {formatDateTime(event.checkin_start_time)}
                    </div>
                  </div>
                </Col>

                <Col md={6}>
                  <div className="payment-summary-box h-100">
                    <div className="text-muted mb-1">Đóng check-in</div>
                    <div className="fw-bold">
                      {formatDateTime(event.checkin_end_time)}
                    </div>
                  </div>
                </Col>
              </Row>
            </Card.Body>
          </Card>

          <Card className="payment-card mt-4">
            <Card.Body className="p-4 p-lg-5">
              <div className="section-title mb-2" style={{ fontSize: "1.7rem" }}>
                Chọn loại vé
              </div>
              <div className="section-subtitle mb-4">
                Chọn số lượng vé phù hợp trước khi tạo đơn hàng.
              </div>

              {ticketTypes.length === 0 ? (
                <Alert variant="warning">
                  Hiện chưa có loại vé nào cho sự kiện này.
                </Alert>
              ) : (
                <div className="d-flex flex-column gap-3">
                  {ticketTypes.map((ticket) => {
                    const maxAllowed = Math.min(
                      Number(ticket.available || 0),
                      Number(ticket.max_per_order || 0)
                    );

                    return (
                      <Card key={ticket.id} className="user-card border-0">
                        <Card.Body className="p-4">
                          <Row className="align-items-center g-3">
                            <Col md={8}>
                              <div className="d-flex flex-wrap align-items-center gap-2 mb-2">
                                <h5 className="fw-bold mb-0">{ticket.name}</h5>
                                <Badge
                                  bg={
                                    ticket.status === "active"
                                      ? "success"
                                      : "secondary"
                                  }
                                  className="status-badge"
                                >
                                  {ticket.status === "active"
                                    ? "Đang bán"
                                    : "Ngưng bán"}
                                </Badge>
                              </div>

                              <div className="text-muted mb-2">
                                {ticket.description || "Không có mô tả"}
                              </div>

                              <div className="d-flex flex-wrap gap-3 text-muted">
                                <span>
                                  <strong>Giá:</strong>{" "}
                                  {Number(ticket.price || 0).toLocaleString(
                                    "vi-VN"
                                  )}{" "}
                                  VND
                                </span>
                                <span>
                                  <strong>Còn lại:</strong>{" "}
                                  {ticket.available ?? 0}
                                </span>
                                <span>
                                  <strong>Tối đa mỗi đơn:</strong>{" "}
                                  {ticket.max_per_order ?? 0}
                                </span>
                                <span>
                                  <strong>Chuyển nhượng:</strong>{" "}
                                  {Number(ticket.transferable) === 1
                                    ? "Có"
                                    : "Không"}
                                </span>
                              </div>
                            </Col>

                            <Col md={4}>
                              <Form.Group>
                                <Form.Label className="fw-semibold">
                                  Số lượng
                                </Form.Label>
                                <Form.Control
                                  type="number"
                                  min={0}
                                  max={maxAllowed}
                                  value={quantities[ticket.id] || 0}
                                  onChange={(e) =>
                                    handleQuantityChange(ticket, e.target.value)
                                  }
                                  disabled={maxAllowed <= 0}
                                />
                              </Form.Group>
                            </Col>
                          </Row>
                        </Card.Body>
                      </Card>
                    );
                  })}
                </div>
              )}
            </Card.Body>
          </Card>
        </Col>

        <Col lg={4}>
          <Card
            className="payment-card"
            style={{ position: "sticky", top: "110px" }}
          >
            <Card.Body className="p-4">
              <div className="section-title mb-3" style={{ fontSize: "1.5rem" }}>
                Tóm tắt đơn hàng
              </div>

              <div className="payment-summary-box mb-3">
                <div className="d-flex justify-content-between mb-2">
                  <span>Tổng loại vé</span>
                  <strong>{ticketTypes.length}</strong>
                </div>
                <div className="d-flex justify-content-between mb-2">
                  <span>Tổng số vé</span>
                  <strong>{totalTickets}</strong>
                </div>
                <div className="d-flex justify-content-between">
                  <span>Tổng tiền</span>
                  <strong>
                    {totalAmount.toLocaleString("vi-VN")} VND
                  </strong>
                </div>
              </div>

              {summary && (
                <div className="payment-summary-box mb-4">
                  <div className="d-flex justify-content-between mb-2">
                    <span>Tổng số lượng vé</span>
                    <strong>{summary.totalQuantity ?? 0}</strong>
                  </div>
                  <div className="d-flex justify-content-between mb-2">
                    <span>Đã bán</span>
                    <strong>{summary.totalSold ?? 0}</strong>
                  </div>
                  <div className="d-flex justify-content-between">
                    <span>Còn lại</span>
                    <strong>{summary.totalAvailable ?? 0}</strong>
                  </div>
                </div>
              )}

              <div className="d-grid gap-3">
                <Button
                  className="soft-button soft-button-primary"
                  onClick={handleCreateOrder}
                  disabled={!canBuy || totalTickets === 0 || submitting}
                >
                  {submitting ? "Đang tạo đơn..." : "Đặt vé ngay"}
                </Button>

                <Button
                  className="soft-button soft-button-dark"
                  onClick={() => navigate("/home")}
                >
                  Quay lại trang chủ
                </Button>
              </div>

              {!user && (
                <Alert variant="warning" className="mt-4 mb-0">
                  Bạn cần đăng nhập trước khi đặt vé.
                </Alert>
              )}
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default EventDetailPage;
